from dataclasses import dataclass

@dataclass
class RateLimitHeaders:
    limit: int          # RateLimit-Limit: policy ceiling
    remaining: int      # RateLimit-Remaining: tokens left this window
    reset: int          # RateLimit-Reset: UNIX timestamp of next window reset
    retry_after: int    # Retry-After: seconds to wait (set only on 429)

    def to_http_headers(self, is_429: bool = False) -> dict[str, str]:
        headers = {
            "RateLimit-Limit": str(self.limit),
            "RateLimit-Remaining": str(self.remaining),
            "RateLimit-Reset": str(self.reset),
            "X-RateLimit-Limit-Requests": str(self.limit),
            "X-RateLimit-Remaining-Requests": str(self.remaining),
        }
        if is_429:
            headers["Retry-After"] = str(self.retry_after)
        return headers

# In your API handler:
allowed, remaining = limiter.consume(key=user_id, cost=1)
headers = RateLimitHeaders(
    limit=100,
    remaining=remaining,
    reset=int(time.time()) + 60,
    retry_after=10,
)
if not allowed:
    return Response(
        status=429,
        body={"error": "rate_limit_exceeded", "message": "Too many requests"},
        headers=headers.to_http_headers(is_429=True),
    )

import asyncio
import time
from collections import deque
from dataclasses import dataclass

@dataclass
class ProviderQuota:
    tpm_limit: int
    rpm_limit: int
    tpm_headroom_pct: float = 0.15   # stop at 85% of TPM limit
    rpm_headroom_pct: float = 0.10   # stop at 90% of RPM limit

    @property
    def effective_tpm(self) -> int:
        return int(self.tpm_limit * (1 - self.tpm_headroom_pct))

    @property
    def effective_rpm(self) -> int:
        return int(self.rpm_limit * (1 - self.rpm_headroom_pct))

class AdaptiveProviderClient:
    def __init__(self, quota: ProviderQuota):
        self.quota = quota
        self._token_window: deque[tuple[float, int]] = deque()
        self._req_window: deque[float] = deque()
        self._lock = asyncio.Lock()

    def _prune_windows(self, now: float) -> None:
        cutoff = now - 60.0
        while self._token_window and self._token_window[0][0] < cutoff:
            self._token_window.popleft()
        while self._req_window and self._req_window[0] < cutoff:
            self._req_window.popleft()

    @property
    def current_tpm(self) -> int:
        return sum(t for _, t in self._token_window)

    @property
    def current_rpm(self) -> int:
        return len(self._req_window)

    async def wait_for_capacity(self, estimated_tokens: int) -> None:
        while True:
            async with self._lock:
                now = time.monotonic()
                self._prune_windows(now)
                if (self.current_tpm + estimated_tokens <= self.quota.effective_tpm
                        and self.current_rpm + 1 <= self.quota.effective_rpm):
                    self._token_window.append((now, estimated_tokens))
                    self._req_window.append(now)
                    return
            # Proactive back-pressure: sleep 100ms and retry
            await asyncio.sleep(0.1)

    def record_response_tokens(self, actual_tokens: int, estimated_tokens: int) -> None:
        # Correct the estimate with actuals for future accuracy
        delta = actual_tokens - estimated_tokens
        if delta > 0:
            now = time.monotonic()
            self._token_window.append((now, delta))

    async def chat_completion(
        self,
        messages: list[dict],
        model: str,
        estimated_input_tokens: int,
        max_output_tokens: int,
    ) -> dict:
        estimated_total = estimated_input_tokens + max_output_tokens
        await self.wait_for_capacity(estimated_total)
        # ... actual HTTP call to provider ...
        return {}

from dataclasses import dataclass
import math

@dataclass
class CapacityModel:
    peak_rps: float                # requests per second at peak
    p99_latency_s: float           # end-to-end latency in seconds
    safety_factor: float = 1.5     # over-provision by this factor
    queue_headroom_factor: float = 2.0  # queue depth = concurrency * this

    @property
    def concurrency(self) -> int:
        # Little's Law: N = lambda * W
        raw = self.peak_rps * self.p99_latency_s
        return math.ceil(raw * self.safety_factor)

    @property
    def max_queue_depth(self) -> int:
        return math.ceil(self.concurrency * self.queue_headroom_factor)

    @property
    def tpm_requirement(self, avg_tokens_per_req: int = 2500) -> int:
        return math.ceil(self.peak_rps * 60 * avg_tokens_per_req)

    def summary(self) -> dict:
        return {
            "peak_rps": self.peak_rps,
            "concurrency_slots": self.concurrency,
            "max_queue_depth": self.max_queue_depth,
            "tpm_required": self.tpm_requirement,
        }

model = CapacityModel(peak_rps=5.0, p99_latency_s=3.5)
print(model.summary())
